appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const currentData = model.cookies || {};
    const baselineData = model.cookies2 || {};

    // 1. Calculate Top-Level Scores
    // FIX: Extract from 'appsec.security_score' instead of the root
    const currentScore = currentData.appsec?.security_score || 0;
    const baselineScore = baselineData.appsec?.security_score || 0;
    const scoreDelta = currentScore - baselineScore;
    document.getElementById('baseline-score').innerText = baselineScore;
    document.getElementById('current-score').innerText = currentScore;
    const deltaEl = document.getElementById('overall-delta');
    // Negative security score diff = drop in security = bad (negative)
    if (scoreDelta < 0) {
      deltaEl.innerText = `${scoreDelta} pts (Regression)`;
      deltaEl.className = "delta-badge delta-negative";
    } else if (scoreDelta > 0) {
      deltaEl.innerText = `+${scoreDelta} pts (Improved)`;
      deltaEl.className = "delta-badge delta-positive";
    } else {
      deltaEl.innerText = `No Change`;
      deltaEl.className = "delta-badge delta-neutral";
    }

    // Helper to format category data into card format
    const createCategoryData = (name, baselineVal, currentVal, isLowerBetter = true) => {
      let badgeClass = "delta-badge delta-neutral";
      let badgeText = "No Change";
      let diff = currentVal - baselineVal;
      if (currentVal > baselineVal) {
        // Number went UP. If lower is better (like vulnerabilities), it's a negative change
        badgeClass = isLowerBetter ? "delta-badge delta-negative" : "delta-badge delta-positive";
        badgeText = isLowerBetter ? `+${diff} (Risk Increased)` : `+${diff} (Improved)`;
      } else if (currentVal < baselineVal) {
        // Number went DOWN. If lower is better, it's a positive change
        badgeClass = isLowerBetter ? "delta-badge delta-positive" : "delta-badge delta-negative";
        badgeText = isLowerBetter ? `${diff} (Risk Reduced)` : `${diff} (Regression)`;
      }
      return {
        category: name,
        baseline: baselineVal,
        current: currentVal,
        badgeClass: badgeClass,
        badgeText: badgeText
      };
    };

    // Extract real metrics safely from the JSON
    const getHighIssues = data => data.manifest_analysis?.manifest_summary?.high || 0;
    const getWarningIssues = data => data.manifest_analysis?.manifest_summary?.warning || 0;
    const getMalwarePerms = data => data.malware_permissions?.total_malware_permissions || 0;
    const getTrackers = data => data.trackers?.detected_trackers || 0;

    // 2. Generate Delta Data Array
    const deltaData = [createCategoryData("High Severity", getHighIssues(baselineData), getHighIssues(currentData)), createCategoryData("Warnings", getWarningIssues(baselineData), getWarningIssues(currentData)), createCategoryData("Dangerous Perms", getMalwarePerms(baselineData), getMalwarePerms(currentData)), createCategoryData("Trackers", getTrackers(baselineData), getTrackers(currentData))];

    // 3. Populate Delta Cards Container
    const container = document.getElementById('delta-cards-container');
    container.innerHTML = '';
    if (deltaData.length === 0) {
      container.innerHTML = '<div style="grid-column: span 3; text-align: center;">No historical data available.</div>';
      return;
    }
    deltaData.forEach(item => {
      // Create the card container
      const card = document.createElement('div');
      card.className = 'card';

      // Populate the inner HTML of the card based on the CSS specifications
      card.innerHTML = `
                <div class="label">${item.category}</div>
                <div class="comparison-row">${item.baseline} &rarr; ${item.current}</div>
                <div class="${item.badgeClass}">${item.badgeText}</div>
            `;
      container.appendChild(card);
    });
  });
});

